  const ayahs: AyahProps[] = [
    { ayahId: 29, surahNumber: 1, pageNumber: 1, isComplete: true, continuesFromPrev: true, textData: "عَبْدِنَا فَاتُواْ بِسُورَةٍ مِّن مِّثْلِهِؐ/ وَادْعُواْ شُهَدَآءَكُم مِّن دُونِ ۱للَّهِ إِن كُنتُمْ صَـٰدِقِـينَؐ" },
    { ayahId: 30, surahNumber: 1, pageNumber: 1, isComplete: true, continuesFromPrev: false, textData: "فَإِن لَّمْ تَفْعَلُواْ وَلَن تَفْعَلُــواْ فَاتَّقُواْ ۴لنَّـارَ ۰لتِى وَقُودُهَا ۰لنَّاسُ وَالْحِجَارَةُؐ ٱُعِـدَّتْ لِلْكۭـٰفِـرۣينَؐ" },
    { ayahId: 31, surahNumber: 1, pageNumber: 1, isComplete: true, continuesFromPrev: false, textData: "وَبَشِّرۣ ۱لذِينَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰــتِ أَنَّ لَهُمْ جَنَّـٰــتٍ تَجْرۣﻯ مِن تَحْتِهَا ۰لاَنْهَــٰرُؐ كُلَّمَا رُزۣقُواْ مِنْهَا مِن ثَمَرَةٍ رّۣزْقاً قَالُواْ هَـٰذَا ۰ﻟ﮲ رُزۣقْنَا مِن قَـبْلُؐ وَٱُتُواْ بِهِ” مُتَشَـٰبِهاًؐ وَلَهُمْ فِيهَآ أَزْوَ؛جٌ مُّطَهَّرَةٌؐ وَهُمْ فِيهَا خَـٰلِدُونَؐ ©" },
    { ayahId: 32, surahNumber: 1, pageNumber: 1, isComplete: true, continuesFromPrev: false, textData: "إِنَّ ۰للَّهَ لاَ يَسْتَحْـىِ“ أَنْ يَّضْرۣبَ مَثَلًا مَّا بَعُوضَةً فَمَا فَوْقَهَاؐ فَأَمَّا ۰لذِينَ ءَامَنُواْ فَيَعْلَمُونَ أَنَّهُ ۴لْحَقُّ مِن رَّبِّهِمْؐ وَأَمَّا ۰لذِينَ كَفَرُواْ فَيَقُولُونَ مَاذَآ أَرَادَ ۰للَّهُ بِهَـٰذَا مَثَلًؐا يُضِلُّ بِهِ” كَثِيراً وَيَهْدِى بِهِ” كَثِيراًؐ وَمَا يُضِلُّ بِهِ“ إِلاَّ ۰لْفَــٰسِقِينَ" },
    { ayahId: 33, surahNumber: 1, pageNumber: 1, isComplete: true, continuesFromPrev: false, textData: "۰لذِيـنَ يَنقُضُونَ عَهْدَ ۰للَّهِ مِنۢ بَعْدِ مِيثَـٰقِهِ” وَيَقْطَعُونَ مَآ أَمَرَ ۰للَّهُ بِهِ“ أَنْ يُّوصَلَ وَيُفْسِدُونَ فِى ۱لاَرْضِؐ ﭐُوْلَئِكَ هُمُ ۴لْخَــٰسِرُونَؐ" },
    { ayahId: 34, surahNumber: 1, pageNumber: 1, isComplete: false, continuesFromPrev: false, textData: "كَيْفَ تَكْفُرُونَ بِاللَّهِ وَكُنتُمُ; أَمْوَ؛تاً فَأَحْيۭاكُمْ ثُمَّ يُمِيتُكُمْؐ ثُمَّ يُحْيِيكُمْ ثُمَّ إِلَيْهِ" }
  ];

